import{_ as t,o as l,c as e,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"页面、对话框、抽屉与浮层","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/00-foundations/02-page-dialog-drawer-popover.md","filePath":"03-interaction-design/notes/00-foundations/02-page-dialog-drawer-popover.md","lastUpdated":null}'),s={name:"03-interaction-design/notes/00-foundations/02-page-dialog-drawer-popover.md"};function n(r,a,d,o,h,p){return l(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="页面、对话框、抽屉与浮层" tabindex="-1">页面、对话框、抽屉与浮层 <a class="header-anchor" href="#页面、对话框、抽屉与浮层" aria-label="Permalink to &quot;页面、对话框、抽屉与浮层&quot;">​</a></h1><p>页面、对话框、抽屉和浮层是四种不同的任务容器。选择容器会直接改变 URL、导航历史、焦点范围、背景是否可操作、任务恢复方式和小屏行为。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>容器</th><th>核心特征</th><th>适合</th><th>不适合</th></tr></thead><tbody><tr><td>页面</td><td>独立内容上下文，通常有稳定 URL 和导航位置</td><td>长内容、多步任务、可分享或需刷新恢复的状态</td><td>仅包含一句补充说明的短暂内容</td></tr><tr><td>模态对话框</td><td>位于当前上下文之上，打开后背景不可交互</td><td>必须立即作答的短任务、高风险确认、阻断性选择</td><td>浏览、比较大量内容或长表单</td></tr><tr><td>非模态对话框</td><td>临时窗口，但用户仍可与背景交互</td><td>需要一边参考主内容一边调整的辅助工具</td><td>必须阻止背景修改的原子操作</td></tr><tr><td>抽屉</td><td>从视口边缘出现的面板；可以是模态或非模态</td><td>主对象的详情、筛选、短编辑，且需保留主上下文</td><td>多层导航、复杂多步任务或需独立分享的内容</td></tr><tr><td>浮层</td><td>与触发元素或局部区域关联的轻量临时层</td><td>少量选项、局部控制、补充信息</td><td>关键确认、长内容或不可恢复操作</td></tr></tbody></table><p>“抽屉”和“浮层”主要描述视觉与空间关系，不自动决定模态性。设计规范必须另行说明背景能否操作、焦点是否受限、是否通过外部点击关闭以及关闭是否会丢失输入。</p><p>HTML <code>dialog</code> 与 Popover API 是平台能力，不等于完整的产品决策。<code>dialog.showModal()</code> 会进入顶层并使背景处于不可交互状态；非模态 <code>show()</code> 不会。Popover API 负责显示与隐藏浮层，但内容语义、键盘模型和关闭后的业务结果仍需设计者定义。</p><h2 id="选择机制" tabindex="-1">选择机制 <a class="header-anchor" href="#选择机制" aria-label="Permalink to &quot;选择机制&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;内容是否需要稳定 URL、刷新恢复或长期停留？&quot;] --&gt;|是| P[&quot;页面&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt;|否| B[&quot;是否必须暂停背景任务并立即响应？&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|是| D[&quot;模态对话框&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|否| C[&quot;是否需要保留主内容并承载成组操作？&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| R[&quot;非模态抽屉或面板&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否| O[&quot;锚定触发点的浮层&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个判断只给出初始方案。还要用内容长度、任务风险、设备宽度、深链要求和无障碍行为复核：桌面上的抽屉在窄屏上可能应变成全屏页面；浮层中的内容增长后可能需要升级为对话框或页面。</p><h2 id="各容器必须定义的行为" tabindex="-1">各容器必须定义的行为 <a class="header-anchor" href="#各容器必须定义的行为" aria-label="Permalink to &quot;各容器必须定义的行为&quot;">​</a></h2><h3 id="页面" tabindex="-1">页面 <a class="header-anchor" href="#页面" aria-label="Permalink to &quot;页面&quot;">​</a></h3><ul><li>URL 是否唯一，筛选、分页、选中对象和步骤是否需要写入 URL。</li><li>浏览器前进、后退、刷新和直接打开深链时恢复什么状态。</li><li>页面标题、主标题、导航当前项和焦点落点是否一致。</li><li>加载、空、失败、无权限、对象不存在和过期状态如何显示。</li><li>未保存编辑离开时是自动保存、阻止离开还是允许丢弃。</li></ul><h3 id="模态对话框" tabindex="-1">模态对话框 <a class="header-anchor" href="#模态对话框" aria-label="Permalink to &quot;模态对话框&quot;">​</a></h3><ul><li>打开后焦点进入对话框，<code>Tab</code> 和 <code>Shift+Tab</code> 保持在其中。</li><li>对话框具有可访问名称；标题通常通过 <code>aria-labelledby</code> 关联。</li><li>背景在视觉、指针、键盘和辅助技术层面都不可操作。</li><li><code>Escape</code>、关闭按钮、取消按钮和遮罩点击的行为必须明确。</li><li>关闭后焦点返回触发控件；若触发控件已消失，则进入符合后续任务的元素。</li><li>未保存输入、异步提交和重复点击期间能否关闭必须定义。</li></ul><p>WAI-ARIA APG 是实现指导，不是规范性设计系统。原生 <code>&lt;dialog&gt;</code> 能处理一部分顶层、焦点和关闭行为，仍需测试实际浏览器与辅助技术组合。</p><h3 id="抽屉" tabindex="-1">抽屉 <a class="header-anchor" href="#抽屉" aria-label="Permalink to &quot;抽屉&quot;">​</a></h3><ul><li>明确是模态还是非模态，不能只靠遮罩颜色暗示。</li><li>说明打开是否改变 URL 或历史记录，浏览器返回键是关闭抽屉还是离开页面。</li><li>非模态抽屉应允许用户在主内容和抽屉间按自然顺序移动焦点。</li><li>模态抽屉遵循对话框的焦点约束、名称和关闭要求。</li><li>宽度应受内容与视口约束；放大到 200% 或窄屏时不能遮挡必要操作。</li></ul><h3 id="浮层" tabindex="-1">浮层 <a class="header-anchor" href="#浮层" aria-label="Permalink to &quot;浮层&quot;">​</a></h3><ul><li>触发控件应暴露展开状态和关联关系；打开、关闭后焦点去向明确。</li><li>纯补充说明不应只能通过悬停获得，键盘焦点和触屏也要可达。</li><li>菜单、列表框、对话框和普通说明具有不同语义与键盘模型，不能统一写成 <code>role=&quot;popover&quot;</code>；ARIA 中没有通用的 <code>popover</code> 角色。</li><li>轻量浮层通常允许轻触外部关闭，但若包含未保存输入，应明确确认或保留策略。</li><li>锚点消失、滚动离屏、窗口缩放和空间不足时，应重新定位或关闭。</li></ul><h2 id="完整案例-在订单列表中修改配送地址" tabindex="-1">完整案例：在订单列表中修改配送地址 <a class="header-anchor" href="#完整案例-在订单列表中修改配送地址" aria-label="Permalink to &quot;完整案例：在订单列表中修改配送地址&quot;">​</a></h2><h3 id="初始需求" tabindex="-1">初始需求 <a class="header-anchor" href="#初始需求" aria-label="Permalink to &quot;初始需求&quot;">​</a></h3><p>用户在订单列表发现地址错误，需要在发货前修正。地址修改需要校验，但不是多步骤流程。</p><h3 id="方案比较" tabindex="-1">方案比较 <a class="header-anchor" href="#方案比较" aria-label="Permalink to &quot;方案比较&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>收益</th><th>代价与风险</th><th>结论</th></tr></thead><tbody><tr><td>独立页面</td><td>可深链、刷新恢复、适合复杂地址</td><td>离开列表上下文，短任务成本较高</td><td>地址规则复杂或需多步验证时使用</td></tr><tr><td>模态对话框</td><td>明确聚焦短任务，防止同时修改列表</td><td>小屏空间有限，必须处理焦点和未保存关闭</td><td>当前场景的默认选择</td></tr><tr><td>抽屉</td><td>可同时看到订单信息</td><td>若为模态，本质接近对话框；若非模态，可能同时改动订单状态</td><td>需要持续比较多个订单字段时使用</td></tr><tr><td>浮层</td><td>打开快、靠近触发点</td><td>地址表单过长，错误信息与软键盘易溢出</td><td>不使用</td></tr></tbody></table><h3 id="对话框状态" tabindex="-1">对话框状态 <a class="header-anchor" href="#对话框状态" aria-label="Permalink to &quot;对话框状态&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关闭</span></span>
<span class="line"><span>  → 打开并加载当前地址</span></span>
<span class="line"><span>  → 可编辑</span></span>
<span class="line"><span>  → 本地校验失败 / 服务端校验中</span></span>
<span class="line"><span>  → 保存成功并关闭 / 保存失败并保留输入</span></span>
<span class="line"><span>  → 取消并关闭</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>具体行为：</p><ol><li>用户在某订单行选择“修改地址”，对话框标题包含订单标识。</li><li>焦点进入标题或第一个需要修改的字段；背景订单列表不可操作。</li><li>提交时禁用重复提交，但不要禁用取消所需的全部退出机制。</li><li>字段错误显示在字段附近，并在提交后提供错误摘要；输入保持不变。</li><li>保存成功后关闭对话框，更新该订单行并通过状态消息宣布“订单 1024 的配送地址已更新”。</li><li>焦点返回该订单行的“修改地址”按钮；若该行因筛选消失，焦点移到列表标题或下一项合理位置。</li></ol><p>小屏验证若发现内容需要多次滚动、软键盘遮挡操作或地址包含多阶段验证，则使用全屏页面，并保留返回订单列表的上下文。</p><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>写清任务目标、内容长度、风险、是否需要比较背景内容。</li><li>列出 URL、刷新恢复、分享、历史记录和返回键要求。</li><li>用选择机制得到候选容器，并记录为何排除其他容器。</li><li>为容器定义打开、初始焦点、Tab 顺序、提交、取消、关闭和焦点恢复。</li><li>补齐初始、加载、成功、失败、无权限、过期和未保存状态。</li><li>在桌面、窄屏、200% 放大和内容增长条件下复核容器是否仍适用。</li><li>将无法由静态稿表达的行为写进交付规范，并通过可运行原型验证。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>用模态对话框展示可以在原页面直接出现的普通说明，制造无必要中断。</li><li>把视觉像抽屉的容器称为“非模态”，但背景实际上被遮罩和焦点锁定。</li><li>将长表单放进浮层，外部点击后直接丢失输入。</li><li>通过 CSS 隐藏对话框，却未执行正确关闭流程，导致背景仍被阻塞。</li><li>关闭对话框后把焦点送到页面顶部，使键盘用户丢失任务位置。</li><li>只在桌面判断容器；小屏、放大、虚拟键盘出现后操作不可见。</li><li>嵌套多个模态层。确有连续决策时，优先合并内容或进入新页面。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>仅用键盘打开、操作和关闭容器，确认焦点可见、顺序合理且不会丢失。</li><li>用屏幕阅读器确认容器名称、模态状态、错误与保存结果可被感知。</li><li>在浏览器执行前进、后退、刷新和直接打开 URL，检查状态恢复符合规范。</li><li>在 320 CSS 像素宽度与 200% 缩放下完成任务，确认内容与关闭控件可达。</li><li>制造慢请求、保存失败、权限改变和触发元素消失，验证输入保留与焦点恢复。</li><li>对比关闭按钮、<code>Escape</code>、遮罩点击和系统返回手势，确认结果一致或差异有明确理由。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“从项目列表快速新建任务”选择容器，完成一份行为规范。</p><p>完成时应满足：</p><ul><li>比较页面、对话框、抽屉和浮层，并用任务要求说明选择理由；</li><li>明确 URL、历史记录、背景交互和小屏转换规则；</li><li>画出至少六个状态及其转换；</li><li>写出打开、Tab、<code>Escape</code>、提交、取消和关闭后的焦点行为；</li><li>覆盖加载失败、重复提交和未保存关闭；</li><li>另一位开发者能依据规范实现，测试者能判断每项行为是否通过。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://html.spec.whatwg.org/multipage/interactive-elements.html" target="_blank" rel="noreferrer">WHATWG HTML Standard：Interactive elements</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/dialog-modal/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Dialog (Modal) Pattern</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-17）</li></ul>`,41)])])}const b=t(s,[["render",n]]);export{u as __pageData,b as default};
